//JDF - Recomendacao.
//1. Procedimento de gravacao de log padrao.
//2. Recomendado para transacoes pequenas, ou alguns campos atualizados via procedimentos. (Ex: Procedure: GravaTransportadoras)
//3. Para Cadastros Completos via transacao, criar um Procedimento especifico (Ex: Transacao: Setor que utiliza prcCarregaLog_Setor e prcGravaLog_Setor)
//4. Sempre que fizer log adicione os campos e tabelas no procedimento prcInicializaLog para cadastro de descrições

if &LogErpRegItmOld <> &LogErpRegItmNew or &LogErpRegTip <> TrnMode.Update
	prcGetDadosBanco.Call(&EmpBdErp, &EmpBdAudit)
	//&Schema = !'auditplus'

	//JDF - ESTA GRAVANDO LOG COM EM OUTRA BASE DE DADOS POR CAUSA DO USE
	if not &EmpBdAudit.IsEmpty() and &EmpBdErp <> &EmpBdAudit
		&SQLSentence = format(!'USE [%1]', &EmpBdAudit)
		Do 'ExecuteSQLQuery'
	EndIF

	if &LogErpRegGUID.IsEmpty()
		&LogErpRegGUID = GUID.NewGuid()

		&LogErpRegKey = &LogErpRegCod1.Trim()  			
		if not &LogErpRegCod2.IsEmpty()
			&LogErpRegKey += ', '+trim(&LogErpRegCod2)
		Endif	
		if not &LogErpRegCod3.IsEmpty()
			&LogErpRegKey += ', '+trim(&LogErpRegCod3)
		Endif

		////&SQLSentence = !"INSERT INTO " + &EmpBdAudit.Trim() + "." + &Schema.Trim() + !".LogErpRegistros (LogErpRegGUID, LogErpEmpCod, LogErpFilCod, LogErpRegCod1, LogErpRegCod2, LogErpRegCod3, LogErpRegKey, LogErpUsuGuid, LogErpDtaHorMod, LogErpTabCod, LogTrnCod, LogErpExt, LogErpRegTip) "
		////&SQLSentence += !" VALUES ('" + trim(&LogErpRegGUID.ToString()) + "'"
		////&SQLSentence += " , " + trim(toformattedString(&EmpCod))
		////&SQLSentence += " , " + trim(toformattedString(&FilCod))
		////&SQLSentence += " , '" + &LogErpRegCod1 + "'"
		////&SQLSentence += " , '" + &LogErpRegCod2 + "'"
		////&SQLSentence += " , '" + &LogErpRegCod3 + "'"
		////&SQLSentence += " , '" + &LogErpRegKey + "'"
		////&SQLSentence += " , '" + &wwpContextUserName + "'"
		////&SQLSentence += !" , GETDATE()" //+ &LogErpDtaHorMod
		////&SQLSentence += " , '" + &TabelaAtualizada + "'"
		////&SQLSentence += " , '" + &ObjetoGeradorLog + "'"
		////&SQLSentence += " , '" + &LogErpExt + "'"
		////&SQLSentence += " , '" + &LogErpRegTip+ "') "
		////Do 'ExecuteSQLQuery'		

		new //ESTA GRAVANDO LOG COM EM OUTRA BASE DE DADOS POR CAUSA DO USE
			LogErpRegGUID = &LogErpRegGUID
			LogErpEmpCod = &EmpCod
			LogErpFilCod = &FilCod
			LogErpRegCod1 = &LogErpRegCod1
			LogErpRegCod2 = &LogErpRegCod2
			LogErpRegCod3 = &LogErpRegCod3
			LogErpRegKey = &LogErpRegKey
			LogErpUsuGuid = &wwpContextUserName
			LogErpDtaHorMod = ServerNow()
			LogErpTabCod = &TabelaAtualizada
			LogTrnCod = &ObjetoGeradorLog
			LogErpExt = &LogErpExt
			LogErpRegTip = &LogErpRegTip
		EndNew
		commit
	Endif

	////&SQLSentence = !"INSERT INTO " + &EmpBdAudit.Trim() + "." + &Schema.Trim() + !".LogErpRegistrosItem (LogErpRegGUID, LogErpTabAtrCod, LogErpRegItmOld, LogErpRegItmNew) "
	////&SQLSentence += !" VALUES ('" + trim(&LogErpRegGUID.ToString()) + "'"
	////&SQLSentence += " , '" + &LogErpTabAtrCod + "'"
	////&SQLSentence += " , '" + &LogErpRegItmOld + "'"
	////&SQLSentence += " , '" + &LogErpRegItmNew+ "') "
	////Do 'ExecuteSQLQuery'

	New
		LogErpRegGUID = &LogErpRegGUID
		LogErpTabAtrCod = &LogErpTabAtrCod
		LogErpRegItmOld = &LogErpRegItmOld
		LogErpRegItmNew = &LogErpRegItmNew
	EndNEw
	Commit

	//JDF - ESTA GRAVANDO LOG COM EM OUTRA BASE DE DADOS POR CAUSA DO USE
	if not &EmpBdAudit.IsEmpty() and &EmpBdErp <> &EmpBdAudit
		&SQLSentence = format(!'USE [%1]', &EmpBdErp)
		Do 'ExecuteSQLQuery'
	EndIF
Endif

Sub 'ExecuteSQLQuery'
	&SqlSentence = &SQLSentence.Trim()
	IF NOT &SqlSentence.isEmpty()
		SQL [!&SqlSentence!]
	ENDIF
	Commit
EndSub
